"use client";

import { useParams } from "next/navigation";
import { useQuery, gql } from "@apollo/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Wallet, ArrowUpRight, ArrowDownLeft, History, PieChart } from "lucide-react";
import { useRealTimePrice } from "@/lib/hooks/useRealTimePrice";

const PORTFOLIO_DETAIL_QUERY = gql`
  query GetPortfolioDetail($id: ID!) {
    portfolio(id: $id) {
      id
      name
      balance
      positions {
        symbol
        quantity
      }
      transactions {
        id
        symbol
        type
        quantity
        price
        timestamp
        balanceTransaction
      }
    }
  }
`;

export default function PortfolioDetailPage() {
    const { id } = useParams();
    const { data, loading, error } = useQuery(PORTFOLIO_DETAIL_QUERY, {
        variables: { id },
    });

    // Debug: Log positions data
    console.log("[DEBUG] Portfolio data:", data?.portfolio);
    console.log("[DEBUG] Positions:", data?.portfolio?.positions);

    // Extract symbols for real-time price updates
    const symbols = data?.portfolio?.positions?.map((pos: any) => pos.symbol) || [];
    console.log("[DEBUG] Subscribing to symbols:", symbols);

    // Get real-time prices
    const prices = useRealTimePrice(symbols);
    console.log("[DEBUG] Real-time prices:", prices);

    if (loading) return <div className="p-10 animate-pulse text-slate-500 font-mono">CARGANDO_PORTAFOLIO_{id}...</div>;
    if (error) return <div className="p-10 text-red-500 font-mono">ERROR: {error.message}</div>;

    const portfolio = data?.portfolio;

    // Calculate average cost basis for each symbol from transactions
    const calculateAvgCost = (symbol: string) => {
        const txs = portfolio?.transactions?.filter((tx: any) => tx.symbol === symbol && tx.type === "BUY") || [];
        if (txs.length === 0) return 0;
        const totalCost = txs.reduce((sum: number, tx: any) => sum + (tx.price * tx.quantity), 0);
        const totalQty = txs.reduce((sum: number, tx: any) => sum + tx.quantity, 0);
        return totalQty > 0 ? totalCost / totalQty : 0;
    };

    // Calculate total portfolio value (cash + assets)
    const positionsUsdValue = portfolio?.positions?.reduce((total: number, pos: any) => {
        const price = prices[pos.symbol] || 0;
        return total + (pos.quantity * price);
    }, 0) || 0;
    const totalPortfolioValue = portfolio?.balance + positionsUsdValue;
    console.log("[DEBUG] Total portfolio value:", totalPortfolioValue, "(cash:", portfolio?.balance, "+ assets:", positionsUsdValue, ")");

    // Calculate total cost basis and performance
    const totalCostBasis = portfolio?.positions?.reduce((total: number, pos: any) => {
        const avgCost = calculateAvgCost(pos.symbol);
        return total + (avgCost * pos.quantity);
    }, 0) || 0;
    const totalPerformance = totalCostBasis > 0 ? ((positionsUsdValue - totalCostBasis) / totalCostBasis) * 100 : 0;
    const performanceColor = totalPerformance >= 0 ? "text-emerald-400" : "text-red-400";
    const performanceSign = totalPerformance >= 0 ? "↑" : "↓";
    console.log("[DEBUG] Total performance:", totalPerformance, "%");

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-700">
            <div className="flex justify-between items-end">
                <div>
                    <h1 className="text-4xl font-bold tracking-tighter uppercase">{portfolio.name}</h1>
                    <p className="text-slate-500 text-sm mt-1 uppercase tracking-widest">ID: {portfolio.id.substring(0, 8)}... // Terminal_Scope: Local</p>
                </div>
                <div className="text-right space-y-1">
                    <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Valor_Total_Portafolio</p>
                    <p className="text-4xl font-black text-white font-mono italic">${totalPortfolioValue.toLocaleString()}</p>
                    <div className="flex items-center justify-end gap-4 mt-2">
                        <div>
                            <p className="text-[10px] text-slate-500 uppercase tracking-widest">Rendimiento</p>
                            <p className={`text-lg font-bold font-mono ${performanceColor}`}>
                                {performanceSign} {Math.abs(totalPerformance).toFixed(2)}%
                            </p>
                        </div>
                        <div className="border-l border-slate-700 pl-4">
                            <p className="text-[10px] text-slate-500 uppercase tracking-widest">Saldo_Efectivo</p>
                            <p className="text-lg font-bold text-slate-300 font-mono">${portfolio.balance.toLocaleString()}</p>
                        </div>
                        <div className="border-l border-slate-700 pl-4">
                            <p className="text-[10px] text-slate-500 uppercase tracking-widest">En_Activos</p>
                            <p className="text-lg font-bold text-emerald-400 font-mono">${positionsUsdValue.toLocaleString()}</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <Card className="glass border-none lg:col-span-1">
                    <CardHeader>
                        <CardTitle className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <PieChart size={14} /> Posiciones_Activas
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        {portfolio.positions.length === 0 ? (
                            <p className="text-slate-600 text-sm italic py-4 text-center">Sin posiciones abiertas.</p>
                        ) : (
                            portfolio.positions.map((pos: any) => {
                                const currentPrice = prices[pos.symbol] || 0;
                                const usdValue = pos.quantity * currentPrice;
                                const avgCost = calculateAvgCost(pos.symbol);
                                const hasPrice = currentPrice > 0;
                                const hasCost = avgCost > 0;
                                const performance = hasCost && hasPrice ? ((currentPrice - avgCost) / avgCost) * 100 : 0;
                                const perfColor = performance >= 0 ? "text-emerald-400" : "text-red-400";
                                const perfSign = performance >= 0 ? "↑" : "↓";
                                
                                console.log(`[DEBUG] Position ${pos.symbol}: qty=${pos.quantity}, price=${currentPrice}, avgCost=${avgCost}, performance=${performance}%`);
                                
                                return (
                                    <div key={pos.symbol} className="flex items-center justify-between p-4 bg-white/5 rounded-2xl border border-white/5 hover:border-white/10 transition-colors">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center font-bold text-xs italic">
                                                {pos.symbol.substring(0, 2)}
                                            </div>
                                            <div>
                                                <p className="font-black text-sm">{pos.symbol}</p>
                                                <p className="text-[10px] text-slate-500 uppercase">En cartera</p>
                                            </div>
                                        </div>
                                        <div className="text-right space-y-1">
                                            <div className="font-mono font-bold text-sm">
                                                {pos.quantity} x ${currentPrice.toFixed(2)}
                                            </div>
                                            <div className={`font-mono font-bold text-xs ${hasPrice ? 'text-emerald-400' : 'text-slate-500'}`}>
                                                ${usdValue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                            </div>
                                            {hasCost && (
                                                <div className={`font-mono text-[10px] ${perfColor}`}>
                                                    {perfSign} {Math.abs(performance).toFixed(2)}%
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                );
                            })
                        )}
                    </CardContent>
                </Card>

                <Card className="glass border-none lg:col-span-2">
                    <CardHeader>
                        <CardTitle className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <History size={14} /> Registro_de_Transacciones
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <Table>
                            <TableHeader className="border-white/5">
                                <TableRow className="hover:bg-transparent border-white/5">
                                    <TableHead className="text-slate-500 uppercase text-[9px] tracking-widest">Fecha</TableHead>
                                    <TableHead className="text-slate-500 uppercase text-[9px] tracking-widest">Operación</TableHead>
                                    <TableHead className="text-slate-500 uppercase text-[9px] tracking-widest">Símbolo</TableHead>
                                    <TableHead className="text-slate-500 uppercase text-[9px] tracking-widest">Cant.</TableHead>
                                    <TableHead className="text-slate-500 uppercase text-[9px] tracking-widest">Precio</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {portfolio.transactions.map((tx: any) => (
                                    <TableRow key={tx.id} className="border-white/5 hover:bg-white/5">
                                        <TableCell className="text-[10px] text-slate-500 font-mono">
                                            {new Date(tx.timestamp).toLocaleDateString()}
                                        </TableCell>
                                        <TableCell>
                                            <Badge className={`uppercase text-[8px] font-bold ${tx.type === "BUY" ? "bg-green-500/10 text-green-400 border-green-500/20" : "bg-red-500/10 text-red-400 border-red-500/20"
                                                }`}>
                                                {tx.type === "BUY" ? "COMPRA" : "VENTA"}
                                            </Badge>
                                        </TableCell>
                                        <TableCell className="font-bold text-xs italic">{tx.symbol}</TableCell>
                                        <TableCell className="font-mono text-xs">{tx.quantity}</TableCell>
                                        <TableCell className="font-mono text-xs text-white">${tx.price?.toLocaleString()}</TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}